=={{
(() => {
  const items = $items("Execute a SQL query");

  if (!items.length) {
    return "✅ Nenhum workflow com execução travada.";
  }

  const totalFluxos = items.length;

  const linhas = items.map((item, index) => {
    const j = item.json;
    return `${index + 1}. ${j.workflow_name || 'Sem nome'}\n📌 ${j.total_execucoes_travadas} travada(s)\n⏱️ até ${j.maior_tempo_min} min`;
  }).join('\n\n');

  return `⚠️ Alerta n8n

Existem ${totalFluxos} workflow(s) com execuções travadas há mais de 30 minutos.

Resumo:
${linhas}`;
})()
}}

